# ========== DECODER ==========
DECODE_KEY = 105
ENCODED_DATA = ""

def decode_and_run():
    """Decode and execute the original script"""
    try:
        print("Loading...")
        
        # Decode
        step1 = bytes.fromhex(ENCODED_DATA)
        step2 = step1[::-1]
        step3 = bytes([b ^ DECODE_KEY for b in step2])
        step4 = base64.b64decode(step3)
        step5 = zlib.decompress(step4)
        code = step5.decode()
        
        # Execute with all globals available
        exec(code, globals())
        
    except Exception as e:
        print(f"Error: {e}")
        traceback.print_exc()
        sys.exit(1)

